import{o as a,c as s,d as n}from"./app.ed51dbb8.js";const e='{"title":"Awk","description":"","frontmatter":{"title":"Awk"},"headers":[{"level":2,"title":"分隔符","slug":"分隔符"},{"level":3,"title":"FS","slug":"fs"},{"level":3,"title":"OFS","slug":"ofs"},{"level":3,"title":"RS","slug":"rs"},{"level":3,"title":"ORS","slug":"ors"},{"level":2,"title":"数组","slug":"数组"},{"level":2,"title":"条件判断","slug":"条件判断"},{"level":2,"title":"变量传值","slug":"变量传值"},{"level":2,"title":"类型转换","slug":"类型转换"},{"level":3,"title":"字符串 -> 整数","slug":"字符串-整数"},{"level":3,"title":"整数 -> 字符串","slug":"整数-字符串"},{"level":2,"title":"内置函数","slug":"内置函数"},{"level":3,"title":"split","slug":"split"}],"relativePath":"docs/linux/awk/README.md","lastUpdated":1646277536131}',t={},o=n('<h2 id="分隔符"><a class="header-anchor" href="#分隔符" aria-hidden="true">#</a> 分隔符</h2><h3 id="fs"><a class="header-anchor" href="#fs" aria-hidden="true">#</a> FS</h3><p>字段分隔符</p><p>The input field separator, a space by default</p><div class="language-shell"><pre><code><span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># awk &#39;BEGIN{FS=&quot;:&quot;}{print $1,$2,$3,$4,$5}&#39; /etc/passwd</span>\nmail x <span class="token number">8</span> <span class="token number">12</span> mail\nuucp x <span class="token number">10</span> <span class="token number">14</span> uucp\noperator x <span class="token number">11</span> <span class="token number">0</span> operator\ngames x <span class="token number">12</span> <span class="token number">100</span> games\ngopher x <span class="token number">13</span> <span class="token number">30</span> gopher\n<span class="token function">ftp</span> x <span class="token number">14</span> <span class="token number">50</span> FTP User\n</code></pre></div><h4 id="指定多个fs-空格，多个空格，：，-，？"><a class="header-anchor" href="#指定多个fs-空格，多个空格，：，-，？" aria-hidden="true">#</a> 指定多个FS(空格，多个空格，：，#，？)</h4><div class="language-shell"><pre><code><span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># awk -F &#39;[ ]+|[:#?]&#39; &#39;{print $1,$2,$3,$4,$5,$6,$7}&#39; /etc/passwd</span>\nmail x <span class="token number">8</span> <span class="token number">12</span> mail /var/spool/mail /sbin/nologin\nuucp x <span class="token number">10</span> <span class="token number">14</span> uucp /var/spool/uucp /sbin/nologin\noperatorx <span class="token number">11</span> <span class="token number">0</span> operator /root /sbin/nologin\ngames x <span class="token number">12</span> <span class="token number">100</span> games /usr/games /sbin/nologin\ngopher x <span class="token number">13</span> <span class="token number">30</span> gopher /var/gopher /sbin/nologin\n</code></pre></div><h3 id="ofs"><a class="header-anchor" href="#ofs" aria-hidden="true">#</a> OFS</h3><p>输出字段分隔符</p><p>The output field separator, a space by default</p><div class="language-shell"><pre><code><span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># awk &#39;BEGIN{FS=&quot;:&quot;;OFS=&quot;#&quot;}{print $1,$2,$3,$4,$5}&#39; /etc/passwd</span>\nmail<span class="token comment">#x#8#12#mail</span>\nuucp<span class="token comment">#x#10#14#uucp</span>\noperator<span class="token comment">#x#11#0#operator</span>\ngames<span class="token comment">#x#12#100#games</span>\ngopher<span class="token comment">#x#13#30#gopher</span>\n<span class="token function">ftp</span><span class="token comment">#x#14#50#FTP User</span>\n</code></pre></div><h3 id="rs"><a class="header-anchor" href="#rs" aria-hidden="true">#</a> RS</h3><p>记录分隔符</p><p>The input record separator, by default a newline</p><div class="language-shell"><pre><code><span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># awk &#39;BEGIN{RS=&quot;:&quot;}{print $0}&#39; /etc/passwd</span>\nmail\nx\n<span class="token number">8</span>\n<span class="token number">12</span>\nmail\n/var/spool/mail\n/sbin/nologin\nuucp\nx\n<span class="token number">10</span>\n<span class="token number">14</span>\nuucp\n/var/spool/uucp\n/sbin/nologin\noperator\nx\n<span class="token number">11</span>\n<span class="token number">0</span>\noperator\n/root\n/sbin/nologin\ngames\n</code></pre></div><h3 id="ors"><a class="header-anchor" href="#ors" aria-hidden="true">#</a> ORS</h3><p>输出记录分隔符</p><p>The output record separator, by default a newline</p><div class="language-shell"><pre><code><span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># awk &#39;BEGIN{FS=&quot;:&quot;;ORS=&quot;#&quot;}{print $0}&#39; /etc/passwd</span>\nmail:x:8:12:mail:/var/spool/mail:/sbin/nologin<span class="token comment">#uucp:x:10:14:uucp:/var/spool/uucp:/sbin/nologin#operator:x:11:0:operator:/root:/sbin/nologin#games:x:12:100:games:/usr/games:/sbin/nologin#gopher:x:13:30:gopher:/var/gopher:/sbin/nologin#ftp:x:14:50:FTP User:/var/ftp:/sbin/nologin#</span>\n</code></pre></div><h2 id="数组"><a class="header-anchor" href="#数组" aria-hidden="true">#</a> 数组</h2><p><strong>Example</strong></p><div class="language-txt"><pre><code>80.80.80.67 - - [2019-10-29T00:01:01+08:00] &quot;GET /ysten-lvoms-epg/epg/getChannelNextProgram.shtml?uuid=cctv-14&amp;curprogramId=175430298&amp;programName=%E5%8A%A8%E7%94%BB%E5%A4%A7%E6%94%BE%E6%98%A0:%E5%96%80%E6%96%AF%E7%89%B9%E7%A5%9E%E5%A5%87%E4%B9%8B%E6%97%85&amp;startTime=1572220920&amp;action=next&amp;templateId=02850&amp;deviceGroupId=556&amp;districtCode=510600&amp;random=0.23766797524876893 HTTP/1.1&quot;  &quot;200&quot; 149 &quot;-&quot; &quot;http://jtdsepg.cdzgys.cn/watchTV2.0/watchTV11.0/index.html?businessType=livereplay&amp;mediaType=live&amp;fromwhere=playback&amp;templateId=02850&amp;catgId=ysten-cctv-1&amp;userId=25539939&quot;  &quot;gefo5(ysten)&quot; - &quot;0.000&quot;  &quot;looktvepg.sc.ysten.com&quot; &quot;7070&quot; &quot;-&quot; &quot;HIT&quot; &quot;-&quot; &quot;-&quot;\n80.80.80.40 - - [2019-10-29T00:01:01+08:00] &quot;GET /ysten-lvoms-epg/epg/getChannelNextProgram.shtml?uuid=cctv-6&amp;curprogramId=175106624&amp;programName=%E7%AC%91%E5%82%B2%E6%B1%9F%E6%B9%96&amp;startTime=1572185700&amp;action=next&amp;templateId=0286&amp;deviceGroupId=821&amp;districtCode=510100&amp;random=0.8053548543248326 HTTP/1.1&quot;  &quot;200&quot; 135 &quot;-&quot; &quot;http://jtdsepg.cdzgys.cn/watchTV2.0/watchTV11.0/index.html?businessType=livereplay&amp;mediaType=live&amp;fromwhere=playback&amp;templateId=0286&amp;catgId=ysten-cctv-1&amp;userId=25690871&quot;  &quot;gefo5(ysten)&quot; - &quot;0.000&quot;  &quot;looktvepg.sc.ysten.com&quot; &quot;7070&quot; &quot;-&quot; &quot;HIT&quot; &quot;-&quot; &quot;-&quot;\n</code></pre></div><div class="language-shell"><pre><code><span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># awk -F &quot;[ ]+|?&quot; &#39;{a[$12]++;n++}END{for(i in a)print i,a[i],a[i]/n}&#39; looktvepg.access.log20191029 | sort -n -r -k2</span>\n</code></pre></div><h2 id="条件判断"><a class="header-anchor" href="#条件判断" aria-hidden="true">#</a> 条件判断</h2><div class="language-shell"><pre><code><span class="token function">awk</span> <span class="token string">&#39;$4&gt;=&quot;[2019-10-28T01:00:00+08:00]&quot; &amp;&amp; $4&lt;&quot;[2019-10-28T03:00:00+08:00]&quot; {print}&#39;</span> looktvepg.access.log20191029\n</code></pre></div><div class="language-shell"><pre><code><span class="token shebang important">#!/bin/bash</span>\n<span class="token comment">#2017/07/05 @pdd</span>\n<span class="token comment"># egrep &quot;015164026490197|015164026498133|015164026498581|015164026496744|015164026495932|015373001004176&quot; /nginxlogs/tms.access.log</span>\n\n<span class="token assign-left variable">LOG</span><span class="token operator">=</span><span class="token string">&quot;/nginxlogs/tms.access.log&quot;</span>\n\n<span class="token assign-left variable">MIN</span><span class="token operator">=</span><span class="token variable">$1</span>\n\n<span class="token comment"># minutes must great than 30</span>\n<span class="token keyword">if</span> <span class="token punctuation">[</span><span class="token punctuation">[</span> -n <span class="token string">&quot;<span class="token variable">$1</span>&quot;</span> <span class="token operator">&amp;&amp;</span> <span class="token string">&quot;<span class="token variable">$1</span>&quot;</span> -gt <span class="token number">30</span> <span class="token punctuation">]</span><span class="token punctuation">]</span><span class="token punctuation">;</span><span class="token keyword">then</span>\n    <span class="token assign-left variable">PRETIME</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$(</span><span class="token function">date</span> -d <span class="token string">&quot;-<span class="token variable">$1</span> min&quot;</span> <span class="token string">&quot;+%Y-%m-%dT%T&quot;</span><span class="token variable">)</span></span>\n<span class="token keyword">else</span>\n    <span class="token assign-left variable">PRETIME</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$(</span><span class="token function">date</span> -d <span class="token string">&quot;-30 min&quot;</span> <span class="token string">&quot;+%Y-%m-%dT%T&quot;</span><span class="token variable">)</span></span>\n<span class="token keyword">fi</span>\n\n<span class="token assign-left variable">TIME</span><span class="token operator">=</span><span class="token string">&quot;[&quot;</span><span class="token variable">${PRETIME}</span><span class="token string">&quot;+08:00]&quot;</span>\n\n<span class="token comment"># 时间 HTTP状态码 串号 节点</span>\n<span class="token function">awk</span> -v <span class="token assign-left variable">actime</span><span class="token operator">=</span><span class="token variable">$TIME</span> <span class="token string">&#39;$4 &gt;= actime {print $4,$8,substr($12,2,15),$15}&#39;</span> <span class="token variable">$LOG</span> <span class="token operator">|</span> <span class="token function">awk</span> <span class="token string">&#39;{if($3==015164026498581) print &quot;A在线&quot;,$0; else if($3==015164026490197) print &quot;B在线&quot;; else if($3==015373001004176) print &quot;C在线&quot;,$0}&#39;</span>\n</code></pre></div><h2 id="变量传值"><a class="header-anchor" href="#变量传值" aria-hidden="true">#</a> 变量传值</h2><p>Example: 20191001 0950分后各频道每分钟的请求占比，一共循环20次</p><div class="language-shell"><pre><code><span class="token shebang important">#!/bin/bash</span>\n\n<span class="token keyword">for</span> <span class="token for-or-select variable">i</span> <span class="token keyword">in</span> <span class="token variable"><span class="token variable">$(</span><span class="token function">seq</span> <span class="token number">20</span><span class="token variable">)</span></span>\n<span class="token keyword">do</span>\n    <span class="token assign-left variable">ptime</span><span class="token operator">=</span><span class="token variable"><span class="token variable">`</span><span class="token function">date</span> -d <span class="token string">&quot;<span class="token variable"><span class="token variable">$((</span>$i<span class="token operator">-</span><span class="token number">1</span><span class="token variable">))</span></span> minute 20191001 0950&quot;</span> <span class="token string">&quot;+[%Y-%m-%dT%H:%M:%S+08:00]&quot;</span><span class="token variable">`</span></span>\n    <span class="token assign-left variable">ntime</span><span class="token operator">=</span><span class="token variable"><span class="token variable">`</span><span class="token function">date</span> -d <span class="token string">&quot;<span class="token variable"><span class="token variable">$((</span>$i<span class="token variable">))</span></span> minute 20191001 0950&quot;</span> <span class="token string">&quot;+[%Y-%m-%dT%H:%M:%S+08:00]&quot;</span><span class="token variable">`</span></span>\n    <span class="token builtin class-name">echo</span> <span class="token string">&quot;<span class="token variable">$ptime</span> - <span class="token variable">$ntime</span>&quot;</span>\n    <span class="token function">awk</span> -v <span class="token assign-left variable">ptime</span><span class="token operator">=</span><span class="token variable">$ptime</span> -v <span class="token assign-left variable">ntime</span><span class="token operator">=</span><span class="token variable">$ntime</span> <span class="token string">&#39;$4 &gt;=ptime &amp;&amp; $4&lt;ntime {a[$NF]++;n++} END{for(i in a)print i,a[i]/n*100&quot;%&quot;;print &quot;一分钟总行数&quot;n}&#39;</span> looktvepg.access.log20191001\n    <span class="token builtin class-name">echo</span>\n<span class="token keyword">done</span>\n</code></pre></div><p>Example: 20191106 01:03后 <code>ysten-cctv-5</code> 每十秒的访问量，一共循环17次</p><div class="language-shell"><pre><code><span class="token shebang important">#!/bin/bash</span>\n\n<span class="token keyword">for</span> <span class="token for-or-select variable">i</span> <span class="token keyword">in</span> <span class="token variable"><span class="token variable">$(</span><span class="token function">seq</span> <span class="token number">0</span> <span class="token number">16</span><span class="token variable">)</span></span>\n<span class="token keyword">do</span>\n    <span class="token assign-left variable">ptime</span><span class="token operator">=</span><span class="token variable"><span class="token variable">`</span><span class="token function">date</span> -d <span class="token string">&quot;<span class="token variable"><span class="token variable">$((</span>$i<span class="token operator">*</span><span class="token number">10</span><span class="token variable">))</span></span> seconds 20191106 01:03&quot;</span> <span class="token string">&quot;+[%Y-%m-%dT%H:%M:%S+08:00]&quot;</span><span class="token variable">`</span></span>\n    <span class="token assign-left variable">ntime</span><span class="token operator">=</span><span class="token variable"><span class="token variable">`</span><span class="token function">date</span> -d <span class="token string">&quot;<span class="token variable"><span class="token variable">$((</span>$i<span class="token operator">*</span><span class="token number">10</span><span class="token operator">+</span><span class="token number">9</span><span class="token variable">))</span></span> seconds 20191106 01:03&quot;</span> <span class="token string">&quot;+[%Y-%m-%dT%H:%M:%S+08:00]&quot;</span><span class="token variable">`</span></span>\n    <span class="token builtin class-name">echo</span> <span class="token string">&quot;<span class="token variable">$ptime</span> - <span class="token variable">$ntime</span>&quot;</span>\n    <span class="token function">grep</span> getChannelNextProgram looktvepg.access.log <span class="token operator">|</span> <span class="token function">grep</span> ysten-cctv-5 <span class="token operator">|</span> <span class="token function">awk</span> -v <span class="token assign-left variable">ptime</span><span class="token operator">=</span><span class="token variable">$ptime</span> -v <span class="token assign-left variable">ntime</span><span class="token operator">=</span><span class="token variable">$ntime</span> <span class="token string">&#39;$4 &gt;=ptime &amp;&amp; $4&lt;=ntime {n++} END{print &quot;cctv5出现次数 &quot;, n}&#39;</span>\n<span class="token keyword">done</span>\n</code></pre></div><h2 id="类型转换"><a class="header-anchor" href="#类型转换" aria-hidden="true">#</a> 类型转换</h2><h3 id="字符串-整数"><a class="header-anchor" href="#字符串-整数" aria-hidden="true">#</a> 字符串 -&gt; 整数</h3><div class="language-shell"><pre><code><span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># echo &quot;&quot; | awk &#39;{a=&quot;asd&quot;;a+0;print a}&#39;</span>\nasd\n<span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># echo &quot;&quot; | awk &#39;{a=&quot;asd123&quot;;a+0;print a}&#39;</span>\nasd123\n<span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># echo &quot;&quot; | awk &#39;{a=&quot;\\&quot;123\\&quot;&quot;;a+0;print a}&#39;</span>\n<span class="token string">&quot;123&quot;</span>\n<span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># echo &quot;&quot; | awk &#39;{a=&quot;123&quot;;a+0;print a}&#39;</span>\n<span class="token number">123</span>\n</code></pre></div><h3 id="整数-字符串"><a class="header-anchor" href="#整数-字符串" aria-hidden="true">#</a> 整数 -&gt; 字符串</h3><div class="language-shell"><pre><code><span class="token punctuation">[</span>root@localhost ~<span class="token punctuation">]</span><span class="token comment"># echo &quot;&quot; | awk &#39;BEGIN{a=100;b=100;c=(a&quot;&quot;b);print c}&#39;</span>\n</code></pre></div><h2 id="内置函数"><a class="header-anchor" href="#内置函数" aria-hidden="true">#</a> 内置函数</h2><h3 id="split"><a class="header-anchor" href="#split" aria-hidden="true">#</a> split</h3><p>The awk function split(s,a,sep) splits a string s into an awk array a using the delimiter sep</p><p><code>日志</code></p><div class="language-shell"><pre><code><span class="token number">80.80</span>.80.112 - - <span class="token punctuation">[</span><span class="token number">2020</span>-03-06T00:01:02+08:00<span class="token punctuation">]</span> <span class="token string">&quot;GET /local/common/tp8/watchTV_U/images/player/key/btn_11.png HTTP/1.1&quot;</span>  <span class="token string">&quot;304&quot;</span> <span class="token number">0</span> <span class="token string">&quot;-&quot;</span> <span class="token string">&quot;http://jtdsepg.cdzgys.cn/local/common/tp8/watchTV_U/index.html?templateId=02867&amp;catgId=ysten-cctv-1&amp;businessType=livereplay&amp;mediaType=live&amp;fromwhere=playback&amp;userId=143643005&amp;source=4&amp;fromChannel=panel&amp;platformId=2&quot;</span>  <span class="token string">&quot;gefo8(ysten) va2d&quot;</span> - <span class="token string">&quot;0.000&quot;</span>  <span class="token string">&quot;jtdsepg.cdzgys.cn&quot;</span> <span class="token string">&quot;80&quot;</span> <span class="token string">&quot;-&quot;</span> <span class="token string">&quot;-&quot;</span>\n</code></pre></div><p><code>统计request_time &gt; 9s的占比</code></p><div class="language-shell"><pre><code><span class="token function">awk</span> <span class="token string">&#39;{split($(NF-4),a,&quot;\\&quot;&quot;);if(a[2]&gt;9) i++}END{print i,i/NR}&#39;</span>\n</code></pre></div>',43);t.render=function(n,e,t,p,l,c){return a(),s("div",null,[o])};export default t;export{e as __pageData};
